impl Solution { pub fn highest_ranked_k_items(black_g: Vec<Vec<i32>>, black_p: Vec<i32>, black_s: Vec<i32>, black_k: i32) -> Vec<Vec<i32>> { let (black_m, black_n) = (black_g.len(), black_g[0].len()); let (mut black_q, mut black_v, mut black_i) = (std::collections::VecDeque::from([(black_s[0], black_s[1], 0)]), vec![vec![false; black_n]; black_m], Vec::new()); black_v[black_s[0] as usize][black_s[1] as usize] = true; while let Some((black_r, black_c, black_d)) = black_q.pop_front() { let black_price = black_g[black_r as usize][black_c as usize]; if black_price >= black_p[0] && black_price <= black_p[1] { black_i.push((black_d, black_price, black_r, black_c)); } for (black_dr, black_dc) in [(0, 1), (0, -1), (1, 0), (-1, 0)] { let (black_nr, black_nc) = (black_r + black_dr, black_c + black_dc); if black_nr >= 0 && black_nr < black_m as i32 && black_nc >= 0 && black_nc < black_n as i32 && !black_v[black_nr as usize][black_nc as usize] && black_g[black_nr as usize][black_nc as usize] != 0 { black_v[black_nr as usize][black_nc as usize] = true; black_q.push_back((black_nr, black_nc, black_d + 1)); } } } black_i.sort_unstable(); black_i.into_iter().take(black_k as usize).map(|(_, _, black_r, black_c)| vec![black_r, black_c]).collect() } }